window.__QUIZ_DATA__=[{"id":"objective>Commerce>1993>1","subject":"Commerce","year":"1993","type":"Objective","topic":"INTRODUCTION TO COMMERCE : MEANING & SCOPE","question":"The function of commerce in production is that it","images":[],"options":{"A":"helps in the extraction of raw materials","B":"provides a link between the different arms of production","C":"is the only branch that satisfies wants","D":"yields results"},"answer":"B","explanation":"The function of commerce in production is to provide a link between the different arms of production. Commerce facilitates the movement of goods and services from producers to consumers, ensuring that production processes are connected and efficient.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>2","subject":"Commerce","year":"1993","type":"Objective","topic":"OCCUPATION : TYPES OF OCCUPATION","question":"Arrange the following occupational activities in the sequences in which they are performed    I. Wholesaling  II. Fishing  III. Canning  IV. Retailing","images":[],"options":{"A":"I, II and IV","B":"III, I, IV and III","C":"II, I, IV and II","D":"II, III, I and IV"},"answer":"D","explanation":"The correct sequence of activities is II (Fishing), III (Canning), I (Wholesaling), and IV (Retailing). Fishing is the primary activity where raw materials are obtained, followed by canning as a processing step, then wholesaling to distribute the products, and finally retailing to sell to consumers.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>3","subject":"Commerce","year":"1993","type":"Objective","topic":"PRODUCTION : MEANING & IMPORTANCE","question":"Which of the following is not a basic want of man?","images":[],"options":{"A":"Transport","B":"Food","C":"Water","D":"Clothing"},"answer":"A","explanation":"Transport is not a basic want of man; rather, it is a means to satisfy basic wants such as food, water, clothing, and shelter. Basic wants are essential for survival, while transport is a service that facilitates access to these wants.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1993>4","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: COMMUNICATION : PROCESS & PROCEDURE","question":"Which of the following comes last in the chain of distribution?","images":[],"options":{"A":"Consumer","B":"Manufacturer","C":"Retailer","D":"Wholesaler"},"answer":"A","explanation":"The consumer comes last in the chain of distribution. The chain typically flows from the manufacturer to the wholesaler, then to the retailer, and finally to the consumer, who is the end user of the product.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>5","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: BANKING : SERVICES & CHALLENGES","question":"Which of the following is not an aid to trade?","images":[],"options":{"A":"Transport","B":"Production","C":"Banking","D":"Insurance"},"answer":"B","explanation":"Production is not considered an aid to trade; rather, it is the process of creating goods and services. Aids to trade include transport, banking, insurance, and warehousing, which support the distribution and sale of products.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>6","subject":"Commerce","year":"1993","type":"Objective","topic":"TRADE : HOME TRADE: RETAIL TRADE","question":"Trade can be described as","images":[],"options":{"A":"Purchase of goods and services","B":"Production of goods","C":"Buying and selling","D":"Distribution of goods"},"answer":"C","explanation":"Trade can be described as 'Buying and selling' because it involves the exchange of goods and services between parties. This definition encompasses the core activities of trade, which is fundamentally about the transaction process.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>7","subject":"Commerce","year":"1993","type":"Objective","topic":"PRODUCTION : MEANING & IMPORTANCE","question":"A system in which people provide their own needs directly is known as","images":[],"options":{"A":"Sub-standard economy","B":"Subsistence economy","C":"Mixed economy","D":"Monetized economy"},"answer":"B","explanation":"A system in which people provide their own needs directly is known as a 'Subsistence economy'. In this type of economy, individuals or communities produce most of what they need to survive, relying on their own resources rather than engaging in trade.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>8","subject":"Commerce","year":"1993","type":"Objective","topic":"PRODUCTION : MEANING & IMPORTANCE","question":"Which of the following is not a branch of production?","images":[],"options":{"A":"Consumption","B":"Extraction","C":"Manufacturing","D":"Distribution"},"answer":"A","explanation":"'Consumption' is not a branch of production. The branches of production typically include extraction (gathering raw materials), manufacturing (creating products), distribution (getting products to consumers), and direct services (providing services directly to consumers). Consumption refers to the use of goods and services, not their production.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>9","subject":"Commerce","year":"1993","type":"Objective","topic":"OCCUPATION : TYPES OF OCCUPATION","question":"In which class of occupation would doctors, teachers and entertainers be grouped?","images":[],"options":{"A":"Extractive","B":"Industrial","C":"Direct service","D":"Commercial"},"answer":"C","explanation":"Doctors, teachers, and entertainers are grouped under 'Direct service' occupations because they provide services directly to individuals or groups, fulfilling immediate needs and demands.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>10","subject":"Commerce","year":"1993","type":"Objective","topic":"OCCUPATION : TYPES OF OCCUPATION","question":"Which of the following occupations come under the extractive industry?    I. Cattle-rearing, lumbering, farming  II. Mining, quarrying and hunting  III. Ship building, road construction, iron beding  IV. Singing, dancing, hair-dressing","images":[],"options":{"A":"I, II and III only","B":"I, II and IV only","C":"I and II only","D":"II, III and IV only"},"answer":"C","explanation":"Occupations that come under the extractive industry include 'I and II only', which are cattle-rearing, lumbering, farming (I) and mining, quarrying, and hunting (II). These activities involve extracting natural resources from the environment. Ship building, road construction, and hair-dressing do not fall under the extractive industry.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>11","subject":"Commerce","year":"1993","type":"Objective","topic":"TRADE : HOME TRADE: RETAIL TRADE","question":"Department stores are usually located","images":[],"options":{"A":"Where low income earners live","B":"In surban towns","C":"At city centers","D":"In low rental areas"},"answer":"C","explanation":"Department stores are typically located at city centers because these areas have high foot traffic and accessibility, which are crucial for attracting customers. City centers often have a diverse population and are easily reachable by public transport, making them ideal for retail businesses.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1993>12","subject":"Commerce","year":"1993","type":"Objective","topic":"PRODUCTION : MEANING & IMPORTANCE","question":"Which of the following statements is true of the manufacturing industry?","images":[],"options":{"A":"The factors of production cannot move to other occupations","B":"It is involved in changing raw materials to finished goods","C":"Its products cannot be distributed to consumers","D":"It does not benefit from the services of direct labour"},"answer":"B","explanation":"The manufacturing industry is primarily involved in transforming raw materials into finished goods. This process includes various stages such as processing, assembling, and packaging, which are essential for creating products that can be sold to consumers.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>13","subject":"Commerce","year":"1993","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT","question":"Any action taken by a company outside its stated objective is regarded as","images":[],"options":{"A":"Caveat vendetta","B":"A trespass","C":"Ultra vires","D":"Uberrimae fidei"},"answer":"C","explanation":"Any action taken by a company outside its stated objectives is referred to as 'ultra vires.' This legal term means 'beyond the powers' and indicates that the company is acting outside the scope of its authority as defined in its corporate charter.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>14","subject":"Commerce","year":"1993","type":"Objective","topic":"LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT","question":"Incorporation simply means the","images":[],"options":{"A":"Floating of a company","B":"Reorganization of company","C":"Birth of a company","D":"Registration of the Memorandum of Association"},"answer":"D","explanation":"Incorporation refers to the legal process of forming a corporation, which includes the registration of the Memorandum of Association. This document outlines the company's objectives, structure, and governance, marking the official birth of the company.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>15","subject":"Commerce","year":"1993","type":"Objective","topic":"BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES","question":"What document is issued by a public limited company when offering shares for sales?","images":[],"options":{"A":"Proposal forms","B":"Policy certificate","C":"Prospectus","D":"Quotation"},"answer":"C","explanation":"A prospectus is a formal document issued by a public limited company when offering shares for sale. It provides detailed information about the company, its financial status, and the terms of the share offering, helping potential investors make informed decisions.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>16","subject":"Commerce","year":"1993","type":"Objective","topic":"BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES","question":"A business unit whose membership ranges from 2 -50 is a","images":[],"options":{"A":"Public corporation","B":"Partnership","C":"Public company","D":"Private company"},"answer":"B","explanation":"A business unit whose membership ranges from 2-50 is typically classified as a Partnership. Partnerships are formed by two or more individuals who agree to share the profits and losses of a business. The other options do not fit this membership criterion.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>17","subject":"Commerce","year":"1993","type":"Objective","topic":"BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES","question":"Founders shares are usually referred to as deferred shares because the holders","images":[],"options":{"A":"Are not entitled to any dividend","B":"Receives their dividends before other shareholders","C":"Are the managers of company","D":"Receive dividends after other shareholders"},"answer":"D","explanation":"Founders shares are often referred to as deferred shares because the holders receive dividends after other shareholders. This means that they are typically paid last in the distribution of dividends, which is why they are considered 'deferred'.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>18","subject":"Commerce","year":"1993","type":"Objective","topic":"BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES","question":"Preference shareholders are different from ordinary shareholders because","images":[],"options":{"A":"Preference shareholders are creditors to the company","B":"The number of shares held by preference shareholders is more","C":"Preference shareholders take a fixed percentage of dividends","D":"The shares of preference shareholders cannot be sold on the stock exchange"},"answer":"C","explanation":"Preference shareholders are different from ordinary shareholders primarily because they receive a fixed percentage of dividends before any dividends are paid to ordinary shareholders. This fixed dividend is a key characteristic of preference shares.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>19","subject":"Commerce","year":"1993","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT","question":"The reward of share holding in a company is","images":[],"options":{"A":"Profit","B":"Dividend","C":"Interest","D":"Bonus"},"answer":"B","explanation":"The reward of shareholding in a company is typically referred to as a Dividend. Dividends are payments made to shareholders out of the company's profits, representing a share of the earnings.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1993>20","subject":"Commerce","year":"1993","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE","question":"Which of the following is not a source of capital to a sole proprietor?","images":[],"options":{"A":"Loan from friends","B":"Personal savings","C":"Ploughing back profit","D":"Borrowing through debentures"},"answer":"D","explanation":"Borrowing through debentures is not a source of capital for a sole proprietor. Debentures are a form of long-term debt instrument used by companies to borrow money, and they are not applicable to sole proprietorships, which typically rely on personal savings, loans from friends, and other personal sources for capital.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>21","subject":"Commerce","year":"1993","type":"Objective","topic":"BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES","question":"Which of the following is not an important reason for government ownership of industries?","images":[],"options":{"A":"Provision of essential services","B":"Large capital requirements","C":"Avoiding duplication of services","D":"Making high profit"},"answer":"D","explanation":"The option 'Making high profit' is not an important reason for government ownership of industries. Governments typically nationalize industries to provide essential services, avoid duplication, and prevent monopolies, rather than to maximize profits.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>22","subject":"Commerce","year":"1993","type":"Objective","topic":"BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES","question":"In a limited partnership, the liability of most of the partners is","images":[],"options":{"A":"Pegged","B":"Unlimited","C":"Limited","D":"Unpredictable"},"answer":"C","explanation":"In a limited partnership, the liability of most partners is 'Limited'. This means that their financial liability is restricted to the amount they invested in the partnership, unlike general partners who have unlimited liability.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>23","subject":"Commerce","year":"1993","type":"Objective","topic":"BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES","question":"The rights, responsibilities and liabilities of each partner are specified in the","images":[],"options":{"A":"Memorandum of association","B":"Prospectus","C":"Articles of association","D":"Deed of partnership"},"answer":"D","explanation":"The rights, responsibilities, and liabilities of each partner in a partnership are specified in the 'Deed of partnership'. This legal document outlines the terms of the partnership agreement.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>24","subject":"Commerce","year":"1993","type":"Objective","topic":"BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES","question":"Which of the following statements is not true?","images":[],"options":{"A":"Government does not nationalize business owned by its citizens","B":"Government nationalizes foreign businesses","C":"Government does not give nationalized industries to private owners","D":"Government nationalizes viable industries"},"answer":"A","explanation":"The statement 'Government does not nationalize business owned by its citizens' is not true. Governments can nationalize businesses owned by citizens, especially in cases where they believe it is in the public interest.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>25","subject":"Commerce","year":"1993","type":"Objective","topic":"BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES","question":"When an industry is nationalized, ownership belongs to the","images":[],"options":{"A":"Shareholders","B":"Government","C":"Tax payers","D":"Indigenes"},"answer":"B","explanation":"When an industry is nationalized, ownership belongs to the 'Government'. Nationalization means that the government takes control of the industry, making it publicly owned rather than privately owned.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>26","subject":"Commerce","year":"1993","type":"Objective","topic":"BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITIES","question":"Which of the following are advantages of indigenization?    I. The economy is controlled by the nationals  II. Entrepreneurial skill is developed  III. Foreigners are encouraged to invest in Nigeria  IV. The standard of living of the indigenes is improved","images":[],"options":{"A":"I and II only","B":"I, II and III only","C":"III and IV only","D":"I, II and IV only"},"answer":"D","explanation":"The advantages of indigenization include that the economy is controlled by the nationals (I), entrepreneurial skills are developed (II), and the standard of living of the indigenes is improved (IV). However, option III is incorrect because indigenization typically discourages foreign investment rather than encouraging it. Therefore, the correct answer is 'I, II and IV only'.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>27","subject":"Commerce","year":"1993","type":"Objective","topic":"NATIONALIZATION AND PRIVATIZATION","question":"One of the main problems of nationalization is that","images":[],"options":{"A":"Nationals may not welcome the change of ownership","B":"Foreigners are not able to control the economy","C":"Repatriation of profit is increased","D":"There may be capital flight"},"answer":"A","explanation":"One of the main problems of nationalization is that nationals may not welcome the change of ownership. This can lead to resistance and lack of support for the nationalized entities, which can hinder their effectiveness and success.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>28","subject":"Commerce","year":"1993","type":"Objective","topic":"NATIONALIZATION AND PRIVATIZATION","question":"The process of selling government business to the public is known as","images":[],"options":{"A":"Naturalization","B":"Nationalization","C":"Privatization","D":"Commercialization"},"answer":"C","explanation":"The process of selling government business to the public is known as privatization. This involves transferring ownership of a public sector enterprise to private individuals or organizations, which is aimed at increasing efficiency and competition.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>29","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: COMMUNICATION : SERVICES","question":"The handling of telephone and telex services is done by","images":[],"options":{"A":"NITEL","B":"NIPOST","C":"COURIER","D":"NEC"},"answer":"A","explanation":"The handling of telephone and telex services is primarily done by NITEL (Nigerian Telecommunications Limited), which was the main telecommunications provider in Nigeria. NIPOST is responsible for postal services, while COURIER, NEC, and NECA do not specifically handle telephone and telex services.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1993>30","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: COMMUNICATION : SERVICES","question":"A Post Office service which provides an alternative to delivery of mails by a postman is the","images":[],"options":{"A":"Post Office Box","B":"Postcode","C":"Post Office Guide","D":"Business Reply Service"},"answer":"A","explanation":"A Post Office service that provides an alternative to delivery of mails by a postman is the Post Office Box. This service allows individuals and businesses to receive their mail at a secure location rather than at their home or office.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1993>31","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: BANKING : SERVICES & CHALLENGES","question":"A service whereby NIPOST undertakes to collect money due to the sender of a parcel is called","images":[],"options":{"A":"C.O.D","B":"C.W.O","C":"C.I.F","D":"F.O.B"},"answer":"A","explanation":"The service where NIPOST collects money due to the sender of a parcel is known as C.O.D (Cash on Delivery). This service allows the sender to receive payment for the parcel upon delivery, ensuring that the sender is compensated before the recipient takes possession of the item.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>32","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES","question":"The cost of advertising a product is ultimately borne by the","images":[],"options":{"A":"Manufacturer","B":"Wholesaler","C":"Agent","D":"Consumer"},"answer":"D","explanation":"The cost of advertising a product is ultimately borne by the consumer. This is because the expenses incurred in advertising are typically passed down the supply chain, leading to higher prices for the end consumer who ultimately pays for the marketing efforts through the price of the product.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>33","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES","question":"Which of the following is used to stimulate sales?","images":[],"options":{"A":"Finance","B":"Insurance","C":"Warehousing","D":"Advertising"},"answer":"D","explanation":"Advertising is used to stimulate sales. It involves promoting a product or service to increase awareness and encourage purchases. Effective advertising can create demand and influence consumer behavior, leading to increased sales.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1993>34","subject":"Commerce","year":"1993","type":"Objective","topic":"ELEMENT OF MARKETING : MEANING AND IMPORTANCE AND FUNCTIONS","question":"Which of the following assigns a name to a product?","images":[],"options":{"A":"Copyright","B":"Packaging","C":"Labelling","D":"Patent"},"answer":"C","explanation":"Labelling is the process that assigns a name to a product. It involves providing information about the product, including its name, ingredients, usage instructions, and other relevant details. Labelling is crucial for branding and consumer recognition.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>35","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: INSURANCE : PRINCIPLES","question":"The insured is prevented from making profit from claims under more than one policy for the same risk by the principle of","images":[],"options":{"A":"Contribution","B":"Subrogation","C":"Utmost good faith","D":"Proximate cause"},"answer":"A","explanation":"The principle of Contribution prevents the insured from making a profit from claims under more than one policy for the same risk. This principle ensures that if a loss occurs, the insured can only recover the actual loss suffered, rather than profiting from multiple insurance claims.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>36","subject":"Commerce","year":"1993","type":"Objective","topic":"ELEMENT OF MARKETING : MARKETING MIX","question":"Which of the following is a form of sales promotion?","images":[],"options":{"A":"Advertising through radio","B":"Advertising by television","C":"Distributing printed sales literature","D":"Offering free samples to customers"},"answer":"D","explanation":"Offering free samples to customers is a direct form of sales promotion as it encourages potential buyers to try a product without any cost, which can lead to increased sales.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>37","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: COMMUNICATION : PROCESS & PROCEDURE","question":"The performance of business activities that directs the flow of goods and services from the producer to the consumer is","images":[],"options":{"A":"Marketing","B":"Merchandising","C":"Transportation","D":"Production"},"answer":"A","explanation":"Marketing is the performance of business activities that directs the flow of goods and services from the producer to the consumer. It encompasses various activities including advertising, sales, and distribution.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>38","subject":"Commerce","year":"1993","type":"Objective","topic":"ELEMENT OF MARKETING : MARKETING MIX","question":"Which of the following is not an element of the marketing mix?","images":[],"options":{"A":"Product","B":"Pricing","C":"Promotion","D":"Purchases"},"answer":"D","explanation":"Purchases are not considered an element of the marketing mix. The marketing mix typically includes Product, Price, Promotion, and Place (the 4 Ps).","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>39","subject":"Commerce","year":"1993","type":"Objective","topic":"BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITIES","question":"The concept that consumers decide what goods and services shall be produced is known as consumer","images":[],"options":{"A":"Protection","B":"Surplus","C":"Sovereignty","D":"Behaviour"},"answer":"C","explanation":"Consumer sovereignty refers to the concept that consumers dictate what goods and services are produced based on their preferences and purchasing decisions.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>40","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: COMMUNICATION : TYPES","question":"A person who sells goods belonging to another person in his own name and received commission is a","images":[],"options":{"A":"Wholesaler","B":"Retailer","C":"Sole trader","D":"Factor"},"answer":"D","explanation":"A factor is a person who sells goods belonging to another person in his own name and receives a commission. This role is distinct from wholesalers and retailers, who typically sell their own goods.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>41","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: INSURANCE : TERMS","question":"When an insured person admits that he has indemnified, he means that","images":[],"options":{"A":"The insurance company has accepted his claims","B":"The damaged property has been recovered","C":"He has paid his premium fully","D":"The insurance company has restored him to his former position"},"answer":"D","explanation":"When an insured person admits that he has indemnified, it means that the insurance company has restored him to his former position. Indemnification in insurance refers to the process of compensating the insured for their loss, thereby restoring them to the financial state they were in before the loss occurred.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>42","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: BANKING : SERVICES & CHALLENGES","question":"The difference between an overdraft and a loan is that an overdraft","images":[],"options":{"A":"Does not yield interest","B":"Is given to savings account holders only","C":"Yields interest on the total balance in the account","D":"Yields interest only on the sum drawn"},"answer":"D","explanation":"The difference between an overdraft and a loan is that an overdraft yields interest only on the sum drawn. An overdraft allows a customer to withdraw more money than they have in their account, and interest is charged only on the amount overdrawn, unlike a loan which typically has a fixed interest rate on the entire amount borrowed.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>43","subject":"Commerce","year":"1993","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL","question":"The excess value of the assets of a business owner its liabilities is","images":[],"options":{"A":"Capital owned","B":"Working capital","C":"Issued capital","D":"Liquid capital"},"answer":"A","explanation":"The excess value of the assets of a business over its liabilities is referred to as capital owned. This represents the net worth of the business, which is calculated by subtracting total liabilities from total assets.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>44","subject":"Commerce","year":"1993","type":"Objective","topic":"MONEY : FUNCTIONS OF MONEY","question":"Cash is said to be legal tender because it","images":[],"options":{"A":"Can be converted into money order","B":"Can be offered and accepted for payment","C":"Is negotiable","D":"Also takes the form of bank draft"},"answer":"B","explanation":"Cash is said to be legal tender because it can be offered and accepted for payment. Legal tender is a medium of payment recognized by the law that must be accepted if offered in payment of a debt.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>45","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: BANKING : SERVICES & CHALLENGES","question":"A cross postal order is","images":[],"options":{"A":"Generally acceptable for payment","B":"Easily converted to cash","C":"The same as money order","D":"Cashed through a post office"},"answer":"D","explanation":"A cross postal order is cashed through a post office. A cross postal order is a type of money order that is crossed, meaning it can only be deposited into a bank account and not cashed directly, which is typically done at a post office.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>46","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: BANKING : TYPES OF BANK","question":"A bank whose name is printed on a cheque leaf is known as the","images":[],"options":{"A":"Drawer","B":"Payer","C":"Drawee","D":"Payee"},"answer":"C","explanation":"The bank whose name is printed on a cheque leaf is known as the Drawee. The drawee is the bank that is responsible for paying the amount specified on the cheque when it is presented for payment.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1993>47","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: INSURANCE : TERMS","question":"A person who wants to undertake an insurance policy usually completes","images":[],"options":{"A":"A proposal form","B":"A promotion form","C":"An application form","D":"An agreement form"},"answer":"A","explanation":"A person who wants to undertake an insurance policy usually completes a proposal form. This form is a formal request for insurance coverage and includes details about the individual and the type of insurance they are seeking.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1993>48","subject":"Commerce","year":"1993","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL","question":"The capital that is needed to meet the day-to-day running of a business is the","images":[],"options":{"A":"Fixed capital","B":"Reserved capital","C":"Circulating capital","D":"Liquid capital"},"answer":"C","explanation":"The capital that is needed to meet the day-to-day running of a business is known as Circulating capital. This type of capital is used for the ongoing operational expenses of a business, such as inventory and wages.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1993>49","subject":"Commerce","year":"1993","type":"Objective","topic":"BUSINESS UNIT: CO-OPERATIVE SOCIETIES : MEANING AND TYPES","question":"An association of local, independent retailers formed to encourage buying in bulk from manufacturers is known as","images":[],"options":{"A":"Voluntary chain","B":"Producer co-operative society","C":"Multiple store","D":"Department store"},"answer":"A","explanation":"An association of local, independent retailers formed to encourage buying in bulk from manufacturers is known as a Voluntary chain. This type of organization allows retailers to benefit from collective purchasing power while maintaining their independence.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>50","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: INSURANCE : TYPES","question":"Third Party Insurance covers, damages","images":[],"options":{"A":"To both passengers and the vehicle","B":"Caused by the vehicle insured","C":"To all parties concerned","D":"To both vehicles involved"},"answer":"C","explanation":"Third Party Insurance covers damages to all parties concerned. This type of insurance protects the insured from claims made by others for damages or injuries caused by the insured's vehicle.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>51","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: BANKING : SERVICES & CHALLENGES","question":"A bank may dishonour a cheque if","images":[],"options":{"A":"It is not crossed","B":"An alteration on the cheque is initial","C":"The amount on the cheques is less than the amount in the account","D":"The amount on the cheque is more than the amount in the account"},"answer":"D","explanation":"A bank may dishonour a cheque if the amount on the cheque is more than the amount in the account. This is because the bank cannot process a cheque that exceeds the available balance, as it would result in an overdraft unless prior arrangements have been made.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>52","subject":"Commerce","year":"1993","type":"Objective","topic":"BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITIES","question":"Which of the following is not one of the 4m's of business resources?","images":[],"options":{"A":"Method","B":"Men","C":"Money","D":"Machine"},"answer":"D","explanation":"The 4M's of business resources typically refer to Men, Money, Material, and Method. 'Machine' is not one of the 4M's, making it the correct answer to the question.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>53","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION","question":"The charge paid for failing to off-load a vehicle within a stipulated time is called","images":[],"options":{"A":"Freight","B":"Demurrage","C":"Fare","D":"Floating charge"},"answer":"B","explanation":"The charge paid for failing to off-load a vehicle within a stipulated time is called 'Demurrage'. Demurrage is a term used in shipping and logistics that refers to the fees incurred when cargo is not loaded or unloaded within the agreed timeframe. This charge compensates the carrier for the additional time the vehicle is held up, which could have been used for other shipments.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>54","subject":"Commerce","year":"1993","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL","question":"The working capital of a company is","images":[],"options":{"A":"Current assets less current liabilities","B":"Fixed assets less current liabilities","C":"Fixed assets less fixed liabilities","D":"Current assets less fixed liabilities"},"answer":"A","explanation":"The working capital of a company is defined as current assets less current liabilities. This measure indicates the short-term financial health of a company and its efficiency in using its assets.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>55","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: COMMUNICATION : MEANING & SCOPE","question":"Which of the following defines communication?","images":[],"options":{"A":"Movement of goods","B":"Transmission of information","C":"Movement of people","D":"Storing of information"},"answer":"B","explanation":"Communication is defined as the transmission of information. This encompasses the exchange of messages, ideas, or data between individuals or groups, which is fundamental in both personal and business contexts.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>56","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: COMMUNICATION : MEANING & SCOPE","question":"The telephone service through which one can dial any number, local, trunk or overseas is known as","images":[],"options":{"A":"Internal communication system","B":"Standard dialling system","C":"Subscriber's trunk dialling system","D":"International telecommunication"},"answer":"C","explanation":"The telephone service that allows one to dial any number, whether local, trunk, or overseas, is known as the Subscriber's Trunk Dialling (STD) system. This system enables direct dialing without the need for operator assistance, facilitating easier communication over long distances.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>57","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: WAREHOUSING: : ADVANTAGES & DISADVANTAGES OF WAREHOUSING","question":"Which of the following is not a function of warehousing?","images":[],"options":{"A":"Production in anticipation of demand","B":"Availability of goods where needed","C":"Availability of goods when needed","D":"Reduction of price fluctuations"},"answer":"A","explanation":"The function of warehousing includes providing storage facilities, ensuring availability of goods where and when needed, and reducing price fluctuations. However, 'Production in anticipation of demand' is not a function of warehousing; it is related to production planning and inventory management. T","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>58","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: WAREHOUSING: : TYPES & IMPORTANCE","question":"Goods discharged from ships on which import duties have not been paid are kept in the","images":[],"options":{"A":"Ordinary warehouse","B":"Private warehouse","C":"Public warehouse","D":"Bonded warehouse"},"answer":"D","explanation":"Goods discharged from ships on which import duties have not been paid are kept in a 'Bonded warehouse'. This type of warehouse allows for the storage of goods without the payment of duties until they are released for sale. Therefore, the correct option is E.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>59","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: COMMUNICATION : SERVICES","question":"The machine used in sending telex messages is known as","images":[],"options":{"A":"Photocopier","B":"Typewriter","C":"Teleprinter","D":"Punching machine"},"answer":"C","explanation":"The machine used in sending telex messages is known as a 'Teleprinter'. A teleprinter is a device that can send and receive typed messages over a communication line, making it suitable for telex communication. Therefore, the correct option is C.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>60","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: COMMUNICATION : SERVICES","question":"which of the following services is not rendered by NIPOST?","images":[],"options":{"A":"Poste Retante","B":"Express delivery","C":"C.W.O","D":"Telegram"},"answer":"C","explanation":"NIPOST (Nigerian Postal Service) provides various services, including registered post, telegrams, express delivery, and Poste Retante. However, 'C.W.O' (which stands for Cash on Delivery) is not a service rendered by NIPOST. Therefore, the correct option is C.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>61","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: COMMUNICATION : SERVICES","question":"Which of the following is the safest means of sending a postal order from Lagos to a friend in Jos?","images":[],"options":{"A":"Registered letter","B":"Recorded delivery","C":"Railex","D":"First class man"},"answer":"A","explanation":"The safest means of sending a postal order from Lagos to a friend in Jos would be through a 'Registered letter'. Registered letters provide a tracking system and require a signature upon delivery, ensuring the safety of the contents. Therefore, the correct option is A.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>62","subject":"Commerce","year":"1993","type":"Objective","topic":"LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION","question":"Which of the following protects consumers against poor quality goods?","images":[],"options":{"A":"Nigerian Chambers of Commerce","B":"Standard Organization of Nigeria","C":"Trade Association","D":"Manufacturing Association of Nigeria"},"answer":"B","explanation":"The Standard Organization of Nigeria (SON) is responsible for setting standards and ensuring the quality of goods and services in Nigeria. It protects consumers by ensuring that products meet certain quality standards, thus safeguarding against poor quality goods.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>63","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION","question":"Which of the following terms of price quotation includes cost of transportation to the buyer's premises?","images":[],"options":{"A":"FOB","B":"C & F","C":"FOR","D":"FAS"},"answer":"B","explanation":"C & F (Cost and Freight) includes the cost of goods and the cost of transportation to the buyer's premises. This term indicates that the seller pays for the transportation of the goods to a specified port, but the risk is transferred to the buyer once the goods are loaded onto the shipping vessel.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>64","subject":"Commerce","year":"1993","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT","question":"Net Profit is the","images":[],"options":{"A":"Excess of income over expenses","B":"Total income from the sale of goods","C":"Difference between sales and purchases","D":"Amount of purchase less closing stock"},"answer":"A","explanation":"Net Profit is defined as the excess of income over expenses. It represents the actual profit made by a business after all costs, including operating expenses, interest, taxes, and depreciation, have been deducted from total revenue.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>65","subject":"Commerce","year":"1993","type":"Objective","topic":"LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT","question":"Who is liable for the contract entered into by the agent on behalf of his principal? The","images":[],"options":{"A":"Agent","B":"Principal","C":"Agent and the principal","D":"Third party"},"answer":"B","explanation":"In a principal-agent relationship, the principal is liable for the contracts entered into by the agent on their behalf, as long as the agent acts within the scope of their authority. The agent acts as a representative of the principal, and thus the principal bears the responsibility for the agent's actions.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>66","subject":"Commerce","year":"1993","type":"Objective","topic":"LEGAL ASPECT OF BUSINESS: HIRE PURCHASES : MEANING AND TYPES","question":"An installmental buying system where ownership immediately transfers to the buyer is known as","images":[],"options":{"A":"Deferred payment","B":"Hire-purchase","C":"Spot buying","D":"Cash sales"},"answer":"B","explanation":"Hire-purchase is an installment buying system where ownership of the goods is transferred to the buyer immediately upon the signing of the agreement, even though payment is made in installments. This contrasts with other systems where ownership is retained by the seller until full payment is made.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>67","subject":"Commerce","year":"1993","type":"Objective","topic":"PURCHASES AND SALES OF GOODS : TERMS OF PAYMENT","question":"A document that is sent to a buyer when credit is not allowed is","images":[],"options":{"A":"Invoice","B":"Consignment note","C":"Debit note","D":"proforma invoice"},"answer":"A","explanation":"An invoice is a document that requests payment for goods or services provided. When credit is not allowed, the seller sends an invoice to the buyer to indicate the amount due for immediate payment.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>68","subject":"Commerce","year":"1993","type":"Objective","topic":"PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING","question":"Which of the following is true of a delivery note? It","images":[],"options":{"A":"Is sent in anticipation of delivery","B":"Does not show the prices of the goods","C":"Gives additional information about the goods","D":"Shows the pictures of goods being delivered"},"answer":"B","explanation":"A delivery note is a document that accompanies a shipment of goods. It typically does not show prices, as its primary purpose is to confirm the delivery of goods and provide details about the items delivered.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>69","subject":"Commerce","year":"1993","type":"Objective","topic":"PURCHASES AND SALES OF GOODS : TERMS OF PAYMENT","question":"A parcel of shoes valued at #2,000 was invoiced0 at #200 only. Which of the following would be used by the seller to correct this error?","images":[],"options":{"A":"An invoice for #2,000","B":"A credit note for #1,800","C":"A debit note for #1,800","D":"A debit note for #2,000"},"answer":"C","explanation":"To correct the invoicing error where a parcel of shoes valued at #2,000 was invoiced at #200, the seller would issue a debit note for the difference. A debit note is used to indicate an increase in the amount owed by the buyer, correcting the original invoice.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>70","subject":"Commerce","year":"1993","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER","question":"An increase in turnover is an increase in","images":[],"options":{"A":"Liquid capital","B":"The volume of sales","C":"Current assets","D":"Fixed assets"},"answer":"B","explanation":"An increase in turnover refers to an increase in the volume of sales. Turnover is a measure of the total sales generated by a business over a specific period, and an increase indicates that the business is selling more products or services.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>71","subject":"Commerce","year":"1993","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT","question":"A retailer's mark-up is","images":[],"options":{"A":"Profit divided by the average stock","B":"Sales divided by the average stock","C":"Gross profit less indirect expenses","D":"The selling price less the cost price"},"answer":"D","explanation":"A retailer's mark-up is defined as the selling price less the cost price. It represents the difference between the cost of goods sold and the price at which they are sold, reflecting the retailer's profit margin.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>72","subject":"Commerce","year":"1993","type":"Objective","topic":"TRADE : FOREIGN TRADE","question":"Foreign trade is also known as","images":[],"options":{"A":"Domestic trade","B":"International trade","C":"Counter trade","D":"Entreport trade"},"answer":"B","explanation":"Foreign trade refers to the exchange of goods and services between countries, which is commonly known as international trade. This term encompasses all trade activities that occur across national borders.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1993>73","subject":"Commerce","year":"1993","type":"Objective","topic":"TRADE : DOCUMENT USED IN INTERNATIONAL TRADE","question":"Which of the following documents in foreign trade states where goods are manufactured?","images":[],"options":{"A":"Bill of lading","B":"Consular invoice","C":"Certificate of Origin","D":"Insurance Certificate"},"answer":"C","explanation":"The Certificate of Origin is a document used in international trade that certifies the country in which the goods were manufactured. It is important for customs purposes and to determine tariffs.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>74","subject":"Commerce","year":"1993","type":"Objective","topic":"STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS","question":"New shares are offered to the public through","images":[],"options":{"A":"Acceptance houses","B":"The stock exchange","C":"Issuing houses","D":"Discount houses"},"answer":"C","explanation":"New shares are typically offered to the public through issuing houses, which are financial institutions that specialize in the issuance of new securities. They help companies raise capital by facilitating the sale of shares.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>75","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION","question":"Speed is an important consideration for the choice of a means of transport where goods are","images":[],"options":{"A":"Bulky","B":"Inferior","C":"Fragile","D":"Perishable"},"answer":"D","explanation":"Speed is particularly crucial for the transport of perishable goods, such as food items, which can spoil quickly. Therefore, choosing a fast means of transport is essential to ensure these goods reach their destination in good condition.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>76","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: TRANSPORTATION : ADVANTAGES & DISADVANTAGES OF TRANSPORTATION","question":"The main disadvantage of water transport is that it","images":[],"options":{"A":"Is safe","B":"Is slow","C":"Can carry heavy goods","D":"Can go long distances"},"answer":"B","explanation":"The main disadvantage of water transport is that it is generally slow compared to other modes of transport, such as air or road transport. While it can carry heavy goods and travel long distances, the speed factor is a significant drawback.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>77","subject":"Commerce","year":"1993","type":"Objective","topic":"BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER","question":"A company that acquires a majority of the shares of other companies with voting rights is regarded as","images":[],"options":{"A":"A consortium","B":"A holding company","C":"An amalgamator","D":"A subsidiary company"},"answer":"B","explanation":"A company that acquires a majority of the shares of other companies with voting rights is known as a holding company. A holding company does not necessarily produce goods or services itself; rather, it owns shares of other companies to control them.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>78","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION","question":"Air transport is of considerable importance today because it","images":[],"options":{"A":"Is faster than other means of transport","B":"Can deliver goods to owner's destination","C":"Is relatively cheaper","D":"Can carry bulky goods"},"answer":"A","explanation":"Air transport is considered important today primarily because it is faster than other means of transport. This speed allows for quick delivery of goods and passengers over long distances, making it a preferred choice for time-sensitive shipments.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>79","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION","question":"When goods are sold, which of the following makes the transfer of ownership effective?","images":[],"options":{"A":"Banking","B":"Transportation","C":"Communication","D":"Warehousing"},"answer":"B","explanation":"The transfer of ownership of goods is made effective through transportation. Once goods are physically delivered to the buyer, ownership is transferred, which is a fundamental principle in sales transactions.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>80","subject":"Commerce","year":"1993","type":"Objective","topic":"TRADE ASSOCIATION : CHAMBER OF COMMERCE","question":"The organization that aims at protecting the business interests of a particular area is the","images":[],"options":{"A":"Trade Association","B":"Manufacturers Association of Nigeria","C":"Chamber of Commerce","D":"Confederation of Industrialists"},"answer":"C","explanation":"The organization that aims at protecting the business interests of a particular area is known as the Chamber of Commerce. This organization advocates for the interests of businesses in a specific region and provides support and resources to its members.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>81","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: TRANSPORTATION : ADVANTAGES & DISADVANTAGES OF TRANSPORTATION","question":"Which of the following are advantages of road over air transport?    I. Flexibility  II. Speed  III. Cost  IV. Delivery to owners destination  V. Comfort","images":[],"options":{"A":"I, III and IV only","B":"I, II, III and V only","C":"II, III and V only","D":"I, II and IV only"},"answer":"A","explanation":"The advantages of road transport over air transport include flexibility, cost-effectiveness, and the ability to deliver directly to the owner's destination. While speed is generally an advantage of air transport, road transport offers more flexibility in routes and schedules, making it suitable for many types of deliveries.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>82","subject":"Commerce","year":"1993","type":"Objective","topic":"BUSINESS UNIT: CO-OPERATIVE SOCIETIES : MEANING AND TYPES","question":"A group of persons that agrees to pool its resources to achieve a particular objective is known as a","images":[],"options":{"A":"Consortium","B":"Holding company","C":"Cartel","D":"Trust"},"answer":"A","explanation":"A consortium is a group of individuals or organizations that come together to pool their resources for a common goal. This aligns with the definition provided in the question.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1993>83","subject":"Commerce","year":"1993","type":"Objective","topic":"BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER","question":"If a motor assembly  plant absorbs a tyre manufacturing company solely for its tyre needs, such an arrangement is known as","images":[],"options":{"A":"Vertical integration","B":"lateral integration","C":"Horizontal integration","D":"Diagonal integration"},"answer":"A","explanation":"Vertical integration occurs when a company expands its operations into different stages of production within the same industry. In this case, the motor assembly plant absorbing a tyre manufacturing company for its tyre needs is an example of vertical integration.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>84","subject":"Commerce","year":"1993","type":"Objective","topic":"TRADE ASSOCIATION : MEANING & FUNCTIONS","question":"Which of the following is formed with a view to fixing output for members so that price is maintained at a high level?","images":[],"options":{"A":"Price Control Board","B":"Chamber of Commerce","C":"Cartels","D":"Holding Companies"},"answer":"C","explanation":"Cartels are formed by a group of producers to regulate production, fix prices, and limit competition among themselves, which helps maintain high prices. This matches the description in the question.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>85","subject":"Commerce","year":"1993","type":"Objective","topic":"TRADE ASSOCIATION : MEANING & FUNCTIONS","question":"Which of the following is not the function of a Trade Association?","images":[],"options":{"A":"Conducting research","B":"Providing technical information","C":"Giving credit facilities","D":"Settling disputes among member"},"answer":"C","explanation":"Trade Associations typically do not provide credit facilities; their primary functions include conducting research, providing technical information, settling disputes among members, and educating members. Therefore, 'Giving credit facilities' is not a function of a Trade Association.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>86","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: COMMUNICATION : PROCESS & PROCEDURE","question":"The act whereby a manager assigns some of his duties and powers t a subordinate is known as","images":[],"options":{"A":"Authority","B":"Assignment","C":"Decision making","D":"Delegation"},"answer":"D","explanation":"Delegation is the process by which a manager assigns some of their responsibilities and authority to subordinates. This is the correct term for the action described in the question.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>87","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: BANKING : SERVICES & CHALLENGES","question":"Which of the following is a compulsory requirement by the commercial banks when granting loans to customers?","images":[],"options":{"A":"Collateral","B":"Referee","C":"Interest","D":"Insurance"},"answer":"A","explanation":"Collateral is a compulsory requirement for commercial banks when granting loans. It serves as security for the loan, ensuring that the bank can recover its funds in case the borrower defaults.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>88","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES","question":"One advantage of personal selling is the","images":[],"options":{"A":"Low cost","B":"Immediate feedback","C":"Appeal to many people at a time","D":"Self service"},"answer":"B","explanation":"One advantage of personal selling is the immediate feedback it provides. Sales representatives can engage directly with customers, allowing them to address concerns and adjust their sales approach in real-time.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>89","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: INSURANCE : TERMS","question":"An author's exclusive right to his published and unpublished work is known as","images":[],"options":{"A":"Patent right","B":"Fundamental human right","C":"Copy right","D":"Authorship"},"answer":"C","explanation":"An author's exclusive right to his published and unpublished work is known as copyright. Copyright protects the creator's intellectual property, allowing them to control the use and distribution of their work.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>90","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA","question":"Which of the following media combines the advantages of sound and motion?","images":[],"options":{"A":"Radio","B":"Neon sign","C":"Bill Board","D":"Television"},"answer":"D","explanation":"Television combines the advantages of sound and motion, making it a powerful medium for communication and advertising. It engages viewers through both auditory and visual stimuli.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>91","subject":"Commerce","year":"1993","type":"Objective","topic":"LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT","question":"Which of the following is not an essential element of a contract?","images":[],"options":{"A":"Offer and acceptance","B":"All contracts must be in writing","C":"Intention to create legal relations","D":"legality of the object"},"answer":"B","explanation":"Not all contracts must be in writing to be valid; many can be oral or implied. The essential elements of a contract include offer and acceptance, intention to create legal relations, legality of the object, and consideration.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>92","subject":"Commerce","year":"1993","type":"Objective","topic":"ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.","question":"What is the total number of the member countries of ECOWAS?","images":[],"options":{"A":"14","B":"15","C":"16","D":"17"},"answer":"B","explanation":"The Economic Community of West African States (ECOWAS) has 15 member countries. This organization was established to promote economic integration and cooperation among its member states.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1993>93","subject":"Commerce","year":"1993","type":"Objective","topic":"TRADE : BALANCE OF PAYMENT","question":"Which of the following measures cannot be used to correct a balance of payment deficit in Nigeria?","images":[],"options":{"A":"Imposing import licenses","B":"Devaluing the Naira","C":"Placing total ban on some commodities","D":"Increasing imports"},"answer":"D","explanation":"Increasing imports cannot be used to correct a balance of payment deficit, as it would likely worsen the deficit by increasing the outflow of foreign currency. Other measures like imposing import licenses, devaluing the Naira, and increasing import duties are typically used to reduce imports and improve the balance of payments.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>1993>94","subject":"Commerce","year":"1993","type":"Objective","topic":"PURCHASES AND SALES OF GOODS : TERMS OF PAYMENT","question":"A foreign bill of exchange is drawn by the","images":[],"options":{"A":"Importer","B":"Shipping and forwarding agent","C":"Importer's bank","D":"Exporter"},"answer":"D","explanation":"A foreign bill of exchange is typically drawn by the exporter. This document is used in international trade to facilitate payment for goods and services, and it represents a promise to pay a specified amount at a future date.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>95","subject":"Commerce","year":"1993","type":"Objective","topic":"ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.","question":"The main objective of ECOWAS is","images":[],"options":{"A":"Promoting economic cooperation and development","B":"Promoting industry","C":"Promoting transport","D":"Promoting agricultural production"},"answer":"A","explanation":"The main objective of ECOWAS is to promote economic cooperation and development among its member states. This includes fostering trade, investment, and economic growth in the region.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1993>96","subject":"Commerce","year":"1993","type":"Objective","topic":"TRADE : HOME TRADE: WHOLESALE TRADE","question":"The retailer operates from a stall while the wholesaler operates from a","images":[],"options":{"A":"Supermarket","B":"Mobile shop","C":"Hypermarket","D":"Warehouse"},"answer":"D","explanation":"The retailer typically operates from a stall or a shop, while the wholesaler operates from a warehouse. A warehouse is a large building where goods are stored before being distributed to retailers or customers.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1993>97","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: INSURANCE : TERMS","question":"Which of the following is not an insurable risk?","images":[],"options":{"A":"Fire accident","B":"Life assurance","C":"Burglary","D":"Loss of profit"},"answer":"D","explanation":"Loss of profit is not an insurable risk because it is not a direct physical loss or damage. Insurable risks typically involve tangible assets or liabilities, while loss of profit is a financial consequence that arises from other events, such as a fire or burglary.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>98","subject":"Commerce","year":"1993","type":"Objective","topic":"AIDS TO TRADE: BANKING : SERVICES & CHALLENGES","question":"Which of the following is the basic function of a Personnel Department?","images":[],"options":{"A":"Recruiting staff","B":"Organizing training for staff dependents","C":"Settling disputes among trade unions","D":"Processing staff salaries and wages"},"answer":"A","explanation":"The basic function of a Personnel Department is recruiting staff. This involves identifying staffing needs, attracting candidates, and selecting individuals to fill those positions, which is fundamental to the department's role in managing human resources.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>99","subject":"Commerce","year":"1993","type":"Objective","topic":"ELEMENTS OF BUSINESS MANAGEMENT : PRINCIPLE","question":"The management techniques that anticipates the future and determines the appropriate line of action is known as","images":[],"options":{"A":"Planning","B":"Organizing","C":"Consulting","D":"Directing"},"answer":"A","explanation":"Planning is the management technique that anticipates the future and determines the appropriate line of action. It involves setting objectives and outlining the steps necessary to achieve them, which is essential for effective management.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1993>100","subject":"Commerce","year":"1993","type":"Objective","topic":"ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE","question":"Span of control is the","images":[],"options":{"A":"Ability of the supervisor to control the staff","B":"Qualification possessed by the supervisor","C":"Number of staff under the control of a supervisor","D":"Authority of the supervisor to control the staff"},"answer":"C","explanation":"Span of control refers to the number of staff under the control of a supervisor. It is a key concept in organizational structure, as it affects how effectively a supervisor can manage their team and ensure efficient communication and oversight.","marks":"1","difficulty":"2"}];